    45→---
    46→
    47→## 3. Reference Implementation (C)
    48→
    49→All code is kept framework-agnostic, consistent with **Clean Architecture**.  
    50→Dependencies limited to the standard C library (`pthread` for concurrency).
    51→
    52→### 3.1. Public Interface – `include/saga.h`
    53→
    54→```c
    55→#ifndef EDUPAY_SAGA_H
    56→#define EDUPAY_SAGA_H
    57→
    58→#include <stdint.h>
    59→#include <stdbool.h>
    60→
    61→/* ---------- Event Bus ---------------------------------------------------- */
    62→
    63→typedef enum {
    64→    EVT_SAGA_STEP_BEGIN,
    65→    EVT_SAGA_STEP_DONE,
    66→    EVT_SAGA_ABORT,
    67→    EVT_SAGA_ROLLBACK_DONE,
    68→    EVT_SAGA_SUCCESS
    69→} saga_event_type_t;
    70→
    71→typedef struct {
    72→    saga_event_type_t type;
    73→    uint64_t          saga_id;
    74→    const char       *step_name;   /* e.g., "FX_Conversion" */
    75→    void             *payload;     /* opaque domain state   */
    76→} saga_event_t;
    77→
    78→/* Subscriber callback signature */
    79→typedef void (*event_handler_f)(const saga_event_t *evt, void *ctx);
    80→
    81→/* Registers a handler; returns 0 on success, -1 on error */
    82→int eventbus_subscribe(event_handler_f cb, void *ctx);
    83→
    84→/* Broadcasts event to all subscribers; thread-safe */
    85→int eventbus_publish(const saga_event_t *evt);
    86→
    87→/* ---------- Saga Orchestrator ------------------------------------------- */
    88→
    89→#define SAGA_MAX_STEPS 8
    90→#define SAGA_STEP_NAME_MAX 32
    91→
    92→typedef int (*saga_step_f)(uint64_t saga_id, void **payload);
    93→typedef int (*saga_comp_f)(uint64_t saga_id, void *payload);
    94→
    95→typedef struct {
    96→    char         name[SAGA_STEP_NAME_MAX];
    97→    saga_step_f  action;
    98→    saga_comp_f  compensate;
    99→} saga_step_def_t;
   100→
   101→typedef struct {
   102→    uint64_t        id;
   103→    uint8_t         step_count;
   104→    uint8_t         current;
   105→    saga_step_def_t steps[SAGA_MAX_STEPS];
   106→    bool            aborted;
   107→} payment_saga_t;
   108→
   109→/* Initializes a saga with the supplied steps */
   110→void saga_init(payment_saga_t *saga, uint64_t id,
   111→               const saga_step_def_t *steps,
   112→               uint8_t step_count);
   113→
   114→/* Executes saga synchronously; returns 0 on success, -1 on failure */
   115→int saga_execute(payment_saga_t *saga);
   116→
   117→#endif /* EDUPAY_SAGA_H */
   118→```
   119→
   120→### 3.2. Core Implementation – `src/saga.c`
   121→
   122→```c
   123→#include "saga.h"
   124→#include <pthread.h>
   125→#include <stdio.h>
   126→#include <stdlib.h>
   127→#include <string.h>
   128→
   129→#define BUS_MAX_HANDLERS 16
   130→
   131→/* ----------------- Simple In-Process Event Bus -------------------------- */
   132→
   133→typedef struct {
   134→    event_handler_f cb;
   135→    void           *ctx;
   136→} handler_entry_t;
   137→
   138→static handler_entry_t BUS[BUS_MAX_HANDLERS];
   139→static pthread_mutex_t BUS_LOCK = PTHREAD_MUTEX_INITIALIZER;
   140→
   141→int eventbus_subscribe(event_handler_f cb, void *ctx)
   142→{
   143→    pthread_mutex_lock(&BUS_LOCK);
   144→    for (int i = 0; i < BUS_MAX_HANDLERS; ++i) {
   145→        if (BUS[i].cb == NULL) {
   146→            BUS[i].cb  = cb;
   147→            BUS[i].ctx = ctx;
   148→            pthread_mutex_unlock(&BUS_LOCK);
   149→            return 0;
   150→        }
   151→    }
   152→    pthread_mutex_unlock(&BUS_LOCK);
   153→    return -1; /* No slots */
   154→}
   155→
   156→int eventbus_publish(const saga_event_t *evt)
   157→{
   158→    pthread_mutex_lock(&BUS_LOCK);
   159→    handler_entry_t handlers[BUS_MAX_HANDLERS];
   160→    memcpy(handlers, BUS, sizeof(handlers));
   161→    pthread_mutex_unlock(&BUS_LOCK);
   162→
   163→    for (int i = 0; i < BUS_MAX_HANDLERS; ++i) {
   164→        if (handlers[i].cb)
   165→            handlers[i].cb(evt, handlers[i].ctx);
   166→    }
   167→    return 0;
   168→}
   169→
   170→/* ----------------- Saga Orchestration ---------------------------------- */
   171→
   172→static void publish_step_event(saga_event_type_t type,
   173→                               const payment_saga_t *saga,
   174→                               const char *step_name,
   175→                               void *payload)
   176→{
   177→    saga_event_t evt = {
   178→        .type      = type,
   179→        .saga_id   = saga->id,
   180→        .step_name = step_name,
   181→        .payload   = payload
   182→    };
   183→    eventbus_publish(&evt);
   184→}
   185→
   186→void saga_init(payment_saga_t *s, uint64_t id,
   187→               const saga_step_def_t *steps,
   188→               uint8_t step_count)
   189→{
   190→    memset(s, 0, sizeof(*s));
   191→    s->id         = id;
   192→    s->step_count = step_count > SAGA_MAX_STEPS ? SAGA_MAX_STEPS : step_count;
   193→    memcpy(s->steps, steps, s->step_count * sizeof(saga_step_def_t));
   194→}
   195→
   196→static int rollback(payment_saga_t *saga)
   197→{
   198→    for (int i = saga->current; i >= 0; --i) {
   199→        saga_step_def_t *step = &saga->steps[i];
   200→        if (step->compensate) {
   201→            publish_step_event(EVT_SAGA_ABORT, saga, step->name, NULL);
   202→            if (step->compensate(saga->id, NULL) != 0)
   203→                fprintf(stderr, "⚠  Compensation failed at %s\n", step->name);
   204→        }
   205→    }
   206→    saga_event_t done = {
   207→        .type      = EVT_SAGA_ROLLBACK_DONE,
   208→        .saga_id   = saga->id,
   209→        .step_name = "ROLLBACK"
   210→    };
   211→    eventbus_publish(&done);
   212→    return -1;
   213→}
   214→
   215→int saga_execute(payment_saga_t *saga)
   216→{
   217→    for (saga->current = 0; saga->current < saga->step_count; ++saga->current) {
   218→        saga_step_def_t *step = &saga->steps[saga->current];
   219→
   220→        publish_step_event(EVT_SAGA_STEP_BEGIN, saga, step->name, NULL);
   221→
   222→        void *payload = NULL;
   223→        if (step->action(saga->id, &payload) != 0) {
   224→            fprintf(stderr, "❌  Saga %lu failed at step %s\n",
   225→                    saga->id, step->name);
   226→            saga->aborted = true;
   227→            return rollback(saga);
   228→        }
   229→
   230→        publish_step_event(EVT_SAGA_STEP_DONE, saga, step->name, payload);
   231→    }
   232→
   233→    saga_event_t ok = {
   234→        .type      = EVT_SAGA_SUCCESS,
   235→        .saga_id   = saga->id,
   236→        .step_name = "COMPLETED"
   237→    };
   238→    eventbus_publish(&ok);
   239→    return 0;
   240→}
   241→```
   242→
