   286→### 3.4. Demonstration Driver – `samples/payment_saga.c`
   287→
   288→```c
   289→#include "saga.h"
   290→#include <stdio.h>
   291→#include <stdlib.h>
   292→#include <time.h>
   293→
   294→/* ---------- Step Implementations --------------------------------------- */
   295→extern int fx_convert(uint64_t, void **);
   296→extern int fx_reverse(uint64_t, void *);
   297→
   298→extern int ledger_post(uint64_t, void **);
   299→extern int ledger_reverse(uint64_t, void *);
   300→
   301→static int fraud_score(uint64_t id, void **payload)
   302→{
   303→    (void)payload;
   304→    printf("🕵  Fraud scoring started for saga %lu\n", id);
   305→
   306→    /* Simulate 30% failure rate for classroom chaos monkeys */
   307→    if (rand() % 10 < 3) {
   308→        fprintf(stderr, "🚨  Fraud scoring FAILED (suspicious)\n");
   309→        return -1;
   310→    }
   311→
   312→    printf("✅  Fraud scoring passed\n");
   313→    return 0;
   314→}
   315→
   316→static int fraud_reverse(uint64_t id, void *payload)
   317→{
   318→    (void)payload;
   319→    printf("↩  Fraud scoring compensation (unflag) for saga %lu\n", id);
   320→    return 0;
   321→}
   322→
   323→/* ---------- Audit Trail Console Subscriber ----------------------------- */
   324→static void audit_logger(const saga_event_t *evt, void *ctx)
   325→{
   326→    (void)ctx;
   327→    const char *type_str[] = {
   328→        "STEP_BEGIN", "STEP_DONE", "ABORT", "ROLLBACK_DONE", "SUCCESS"
   329→    };
   330→    printf("📝  Audit: %s — saga=%lu step=%s\n",
   331→           type_str[evt->type], evt->saga_id, evt->step_name);
   332→}
   333→
   334→int main(void)
   335→{
   336→    srand((unsigned)time(NULL));
   337→    eventbus_subscribe(audit_logger, NULL);
   338→
   339→    saga_step_def_t steps[] = {
   340→        { "FX_Conversion",   fx_convert,   fx_reverse   },
   341→        { "Ledger_Posting",  ledger_post,  ledger_reverse },
   342→        { "Fraud_Scoring",   fraud_score,  fraud_reverse }
   343→    };
   344→
   345→    payment_saga_t saga;
   346→    saga_init(&saga, 42, steps, 3);
   347→
   348→    int rc = saga_execute(&saga);
   349→    printf(rc == 0 ? "🎉  Saga completed successfully!\n"
   350→                   : "💔  Saga rolled back.\n");
   351→    return rc;
   352→}
   353→```
