   125→## 2 ╱ 4 Reference implementation (`compliance_guard.c`)
   126→
   127→```c
   128→/*──────────────────────────────────────────────────────────────────────────────
   129→  compliance_guard.c  —  Internal library for the Compliance micro-service
   130→──────────────────────────────────────────────────────────────────────────────*/
   131→#include "compliance_guard.h"
   132→
   133→#include <openssl/evp.h>
   134→#include <openssl/rand.h>
   135→#include <errno.h>
   136→#include <string.h>
   137→#include <stdlib.h>
   138→#include <stdio.h>
   139→
   140→#define CG_AES_GCM_IV_LEN   12u
   141→#define CG_AES_GCM_TAG_LEN  16u
   142→#define CG_PAN_MAX_LEN      19u     /* ISO/IEC 7812-1 */
   143→#define CG_TOKEN_LEN        19u
   144→
   145→struct cg_key { uint8_t key[32]; };
   146→
   147→/* ───────────────────────────── Internal helpers ─────────────────────────── */
   148→
   149→static int cg_generate_iv(uint8_t *iv, size_t iv_len)
   150→{
   151→    return RAND_bytes(iv, (int)iv_len) == 1 ? 0 : -EIO;
   152→}
   153→
   154→static int cg_validate_luhn(const char *digits)
   155→{
   156→    size_t len = strlen(digits);
   157→    int sum = 0, alt = 0;
   158→
   159→    for (ssize_t i = (ssize_t)len - 1; i >= 0; --i)
   160→    {
   161→        int d = digits[i] - '0';
   162→        if (d < 0 || d > 9) return -EINVAL;
   163→        if (alt) { d *= 2; if (d > 9) d -= 9; }
   164→        sum += d; alt = !alt;
   165→    }
   166→    return sum % 10 == 0 ? 0 : -EINVAL;
   167→}
   168→
   169→static uint8_t cg_rand_digit(void)
   170→{
   171→    uint8_t b; RAND_bytes(&b, 1); return (uint8_t)(b % 10);
   172→}
   173→
   174→static int cg_build_token(const char *pan, char *tok)
   175→{
   176→    size_t len = strlen(pan);
   177→    if (len < 8 || len > CG_PAN_MAX_LEN) return -EINVAL;
   178→
   179→    memcpy(tok, pan, 6);                 /* Keep BIN for analytics */
   180→    for (size_t i = 6; i < len - 1; ++i) /* Randomise body         */
   181→        tok[i] = '0' + cg_rand_digit();
   182→
   183→    /* Recalculate Luhn check digit */
   184→    int sum = 0, alt = 1;
   185→    for (ssize_t i = (ssize_t)len - 2; i >= 0; --i)
   186→    {
   187→        int d = tok[i] - '0';
   188→        if (alt) { d *= 2; if (d > 9) d -= 9; }
   189→        sum += d; alt = !alt;
   190→    }
   191→    tok[len - 1] = '0' + ((10 - (sum % 10)) % 10);
   192→    tok[len] = '\0';
   193→    return 0;
   194→}
   195→
   196→/* ───────────────────────────── Public API ───────────────────────────────── */
   197→
   198→int cg_tokenise_pan(const char *pan, char *out_token, size_t out_len)
   199→{
   200→    if (!pan || !out_token)                 return -EINVAL;
   201→    const size_t n = strlen(pan);
   202→    if (n == 0 || n > CG_PAN_MAX_LEN)       return -EINVAL;
   203→    if (out_len < n + 1)                    return -ENOSPC;
   204→    if (cg_validate_luhn(pan) != 0)         return -EINVAL;
   205→
   206→    /* Switchable algorithm for classroom demos */
   207→    if (getenv("EDUPAY_FPE") && *getenv("EDUPAY_FPE") == '1')
   208→    {
   209→        /* Placeholder for format-preserving AES-FF3-1 */
   210→        return cg_build_token(pan, out_token); /* Fallback path */
   211→    }
   212→    return cg_build_token(pan, out_token);
   213→}
   214→
   215→ssize_t cg_seal(cg_key_t      *key,
   216→                const uint8_t *pt,
   217→                size_t         pt_len,
   218→                uint8_t       *out,
   219→                size_t         out_sz)
   220→{
   221→    if (!key || !pt || !out || pt_len == 0)  return -EINVAL;
   222→    const size_t need = CG_AES_GCM_IV_LEN + pt_len + CG_AES_GCM_TAG_LEN;
   223→    if (out_sz < need)                       return -ENOSPC;
   224→
   225→    uint8_t *iv     = out;
   226→    uint8_t *cipher = out + CG_AES_GCM_IV_LEN;
   227→    uint8_t *tag    = cipher + pt_len;
   228→
   229→    if (cg_generate_iv(iv, CG_AES_GCM_IV_LEN) != 0) return -EIO;
   230→
   231→    ssize_t ret = -EIO;
   232→    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
   233→    if (!ctx) return -ENOMEM;
   234→
   235→    do {
   236→        if (EVP_EncryptInit_ex(ctx, EVP_aes_256_gcm(), NULL, NULL, NULL) != 1) break;
   237→        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GCM_SET_IVLEN,
   238→                                CG_AES_GCM_IV_LEN, NULL) != 1)               break;
   239→        if (EVP_EncryptInit_ex(ctx, NULL, NULL, key->key, iv) != 1)           break;
   240→
   241→        int len = 0, total = 0;
   242→        if (EVP_EncryptUpdate(ctx, cipher, &len, pt, (int)pt_len) != 1)       break;
   243→        total += len;
   244→        if (EVP_EncryptFinal_ex(ctx, cipher + total, &len) != 1)              break;
   245→        total += len;
   246→        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GCM_GET_TAG,
   247→                                CG_AES_GCM_TAG_LEN, tag) != 1)               break;
   248→
   249→        ret = CG_AES_GCM_IV_LEN + total + CG_AES_GCM_TAG_LEN;
   250→    } while (0);
   251→
   252→    EVP_CIPHER_CTX_free(ctx);
   253→    return ret;
   254→}
   255→
   256→ssize_t cg_open(cg_key_t      *key,
   257→                const uint8_t *in,
   258→                size_t         in_len,
   259→                uint8_t       *out,
   260→                size_t         out_sz)
   261→{
   262→    if (!key || !in || !out)                         return -EINVAL;
   263→    if (in_len < CG_AES_GCM_IV_LEN + CG_AES_GCM_TAG_LEN) return -EINVAL;
   264→
   265→    const uint8_t *iv     = in;
   266→    const uint8_t *cipher = in + CG_AES_GCM_IV_LEN;
   267→    const size_t   ct_len = in_len - CG_AES_GCM_IV_LEN - CG_AES_GCM_TAG_LEN;
   268→    const uint8_t *tag    = in + in_len - CG_AES_GCM_TAG_LEN;
   269→
   270→    if (out_sz < ct_len)                             return -ENOSPC;
   271→
   272→    ssize_t ret = -EIO;
   273→    EVP_CIPHER_CTX *ctx = EVP_CIPHER_CTX_new();
   274→    if (!ctx) return -ENOMEM;
   275→
   276→    do {
   277→        if (EVP_DecryptInit_ex(ctx, EVP_aes_256_gcm(), NULL, NULL, NULL) != 1) break;
   278→        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GCM_SET_IVLEN,
   279→                                CG_AES_GCM_IV_LEN, NULL) != 1)               break;
   280→        if (EVP_DecryptInit_ex(ctx, NULL, NULL, key->key, iv) != 1)           break;
   281→
   282→        int len = 0, total = 0;
   283→        if (EVP_DecryptUpdate(ctx, out, &len, cipher, (int)ct_len) != 1)      break;
   284→        total += len;
   285→
   286→        if (EVP_CIPHER_CTX_ctrl(ctx, EVP_CTRL_GCM_SET_TAG,
   287→                                CG_AES_GCM_TAG_LEN, (void *)tag) != 1)       break;
   288→        if (EVP_DecryptFinal_ex(ctx, out + total, &len) != 1) {
   289→            ret = -EBADMSG;                                                  break;
   290→        }
   291→        total += len;
   292→        ret = total;
   293→    } while (0);
   294→
   295→    EVP_CIPHER_CTX_free(ctx);
   296→    return ret;
   297→}
   298→
   299→void cg_secure_bzero(void *ptr, size_t len)
   300→{
   301→    if (!ptr || !len) return;
   302→#if defined(__STDC_LIB_EXT1__)
   303→    memset_s(ptr, len, 0, len);
   304→#else
   305→    volatile uint8_t *p = (volatile uint8_t *)ptr;
   306→    while (len--) *p++ = 0;
   307→#endif
   308→}
   309→
   310→cg_key_t *cg_key_acquire(void)
   311→{
   312→    cg_key_t *k = calloc(1, sizeof *k);
   313→    if (!k) return NULL;
   314→
   315→    const char *env = getenv("EDUPAY_COMPLIANCE_KEY");
   316→    if (env && strlen(env) == 64)
   317→    {   /* Hex-decode deterministic, instructor-supplied key */
   318→        for (size_t i = 0; i < 32; ++i)
   319→            sscanf(&env[i * 2], "%2hhx", &k->key[i]);
   320→    }
   321→    else if (RAND_bytes(k->key, sizeof k->key) != 1)
   322→    {
   323→        free(k); k = NULL;
   324→    }
   325→    return k;
   326→}
   327→
   328→void cg_key_release(cg_key_t *key)
   329→{
   330→    if (!key) return;
   331→    cg_secure_bzero(key->key, sizeof key->key);
   332→    free(key);
   333→}
   334→```
   335→
   336→---
   337→
   338→## 3 ╱ 4 End-to-end console demo (`example_usage.c`)
   339→
   340→```c
   341→/* Compile with
   342→ *   cc -std=c11 -Wall -Wextra example_usage.c compliance_guard.c -lcrypto -o demo
   343→ * Run with
   344→ *   EDUPAY_COMPLIANCE_KEY=$(openssl rand -hex 32) ./demo
   345→ */
   346→#include <stdio.h>
   347→#include <string.h>
   348→
   349→#include "compliance_guard.h"
   350→
   351→int main(void)
   352→{
   353→    const char *pan = "4485275742308327"; /* Visa test card */
   354→
   355→    char token[CG_TOKEN_LEN + 1];
   356→    if (cg_tokenise_pan(pan, token, sizeof token) != 0) {
   357→        fprintf(stderr, "Tokenisation failed\n");
   358→        return 1;
   359→    }
   360→    printf("Tokenised PAN  : %s\n", token);
   361→
   362→    cg_key_t *key = cg_key_acquire();
   363→    if (!key) { perror("key_acquire"); return 1; }
   364→
   365→    uint8_t cipher[256];
   366→    ssize_t n_cipher = cg_seal(key,
   367→                               (const uint8_t *)token, strlen(token),
   368→                               cipher, sizeof cipher);
   369→    cg_secure_bzero(token, sizeof token); /* Immediately destroy clear-text */
   370→    if (n_cipher < 0) {
   371→        fprintf(stderr, "Encryption failed: %zd\n", n_cipher);
   372→        cg_key_release(key);
   373→        return 1;
   374→    }
   375→
   376→    uint8_t clear[64];
   377→    ssize_t n_plain = cg_open(key, cipher, (size_t)n_cipher,
   378→                              clear, sizeof clear);
   379→    cg_key_release(key);
   380→
   381→    if (n_plain < 0) {
   382→        fprintf(stderr, "Decryption failed: %zd\n", n_plain);
   383→        return 1;
   384→    }
   385→    printf("Decrypted token: %.*s\n", (int)n_plain, clear);
   386→    cg_secure_bzero(clear, (size_t)n_plain);
   387→
   388→    return 0;
   389→}
   390→```
