   118→## 4  Projection Port (Header Only)
   119→
   120→Define a **Clean-Architecture port** so that multiple storage‐specific adapters can plug in.
   121→
   122→```c
   123→/* =========================================================================
   124→ * File:    include/eduledger/projection.h
   125→ * Purpose: Projection interface for CQRS read models
   126→ * ========================================================================= */
   127→#ifndef EDU_LEDGER_PROJECTION_H
   128→#define EDU_LEDGER_PROJECTION_H
   129→
   130→#include <stdbool.h>
   131→#include <stddef.h>
   132→#include "eduledger/events.h"
   133→
   134→#ifdef __cplusplus
   135→extern "C" {
   136→#endif
   137→
   138→typedef struct ledger_projection ledger_projection_t;
   139→
   140→/* Factory function pointer table */
   141→typedef struct {
   142→    ledger_projection_t* (*open)(const char* dsn, char* errbuf, size_t errlen);
   143→    void                 (*close)(ledger_projection_t*);
   144→    bool                 (*handle_event)(ledger_projection_t*, const ledger_event_t*, char* errbuf, size_t errlen);
   145→    uint64_t             (*last_sequence)(ledger_projection_t*);
   146→} ledger_projection_vtable_t;
   147→
   148→/* Adapter registration (one per .so or static obj) */
   149→bool register_ledger_projection(const ledger_projection_vtable_t* vtable);
   150→
   151→/* Global factory helpers ------------------------------------------------- */
   152→ledger_projection_t* projection_open(const char* dsn, char* errbuf, size_t errlen);
   153→void                 projection_close(ledger_projection_t* proj);
   154→bool                 projection_handle_event(ledger_projection_t* proj, const ledger_event_t* evt, char* errbuf, size_t errlen);
   155→uint64_t             projection_last_sequence(ledger_projection_t* proj);
   156→
   157→#ifdef __cplusplus
   158→}
   159→#endif
   160→#endif /* EDU_LEDGER_PROJECTION_H */
