   165→## 5  In-Memory Stub (Unit-Test Harness)
   166→
   167→Quickly confirm our port by building an **In-Memory projection** before adding SQLite.
   168→
   169→```c
   170→/* =========================================================================
   171→ * File:    src/eduledger/projection_mem.c
   172→ * Purpose: In-Memory projection for fast CI pipelines
   173→ * ========================================================================= */
   174→#include <stdlib.h>
   175→#include <string.h>
   176→#include "eduledger/projection.h"
   177→
   178→typedef struct {
   179→    ledger_projection_t base;
   180→    uint64_t            cursor;
   181→    size_t              payments_total;
   182→} mem_proj_t;
   183→
   184→/* --- Interface implementations ----------------------------------------- */
   185→static ledger_projection_t* mem_open(const char* dsn, char* err, size_t len)
   186→{
   187→    (void)dsn; /* not used */
   188→    mem_proj_t* p = calloc(1, sizeof *p);
   189→    if (!p) {
   190→        strncpy(err, "OOM opening mem projection", len);
   191→        return NULL;
   192→    }
   193→    return (ledger_projection_t*)p;
   194→}
   195→
   196→static void mem_close(ledger_projection_t* obj)
   197→{
   198→    free(obj);
   199→}
   200→
   201→static bool mem_handle(ledger_projection_t* obj, const ledger_event_t* evt, char* err, size_t len)
   202→{
   203→    (void)err; (void)len;
   204→    mem_proj_t* p = (mem_proj_t*)obj;
   205→    /* idempotency: ignore older sequences */
   206→    if (evt->any.hdr.sequence <= p->cursor) return true;
   207→
   208→    switch (evt->any.hdr.type) {
   209→        case EVT_PAYMENT_INITIATED:
   210→            p->payments_total++;
   211→            break;
   212→        default:
   213→            /* other events ignored for demo */
   214→            break;
   215→    }
   216→    p->cursor = evt->any.hdr.sequence;
   217→    return true;
   218→}
   219→
   220→static uint64_t mem_last(ledger_projection_t* obj)
   221→{
   222→    mem_proj_t* p = (mem_proj_t*)obj;
   223→    return p->cursor;
   224→}
   225→
   226→/* --- VTable registration ----------------------------------------------- */
   227→static const ledger_projection_vtable_t VTABLE = {
   228→    .open          = mem_open,
   229→    .close         = mem_close,
   230→    .handle_event  = mem_handle,
   231→    .last_sequence = mem_last,
   232→};
   233→
   234→/* Register at load time (constructor attr works on gcc/clang) */
   235→__attribute__((constructor))
   236→static void register_mem_projection(void)
   237→{
   238→    register_ledger_projection(&VTABLE);
   239→}
   240→```
