   244→## 6  SQLite3 Production Adapter
   245→
   246→The in-memory version is fine for CI but prod needs durability.   
   247→Below is a fully functional **SQLite3 projection** with _idempotent upserts_ and **optimistic concurrency**.
   248→
   249→```c
   250→/* =========================================================================
   251→ * File:    src/eduledger/projection_sqlite.c
   252→ * Purpose: Durable CQRS read model stored in SQLite
   253→ * ========================================================================= */
   254→#define _POSIX_C_SOURCE 200809L
   255→#include <sqlite3.h>
   256→#include <stdio.h>
   257→#include <stdlib.h>
   258→#include <string.h>
   259→#include "eduledger/projection.h"
   260→
   261→#ifndef EDU_SQL_SCHEMA
   262→#define EDU_SQL_SCHEMA                                                     \
   263→    "PRAGMA journal_mode=WAL;"                                             \
   264→    "CREATE TABLE IF NOT EXISTS projection_cursor("                        \
   265→    "   id       INTEGER PRIMARY KEY CHECK (id = 0),"                      \
   266→    "   seq      INTEGER NOT NULL"                                         \
   267→    ");"                                                                   \
   268→    "INSERT OR IGNORE INTO projection_cursor(id, seq) VALUES(0, 0);"       \
   269→    "CREATE TABLE IF NOT EXISTS vw_payments("                              \
   270→    "   payment_id TEXT PRIMARY KEY,"                                      \
   271→    "   student_id TEXT NOT NULL,"                                         \
   272→    "   currency   TEXT NOT NULL,"                                         \
   273→    "   amount_minor INTEGER NOT NULL,"                                    \
   274→    "   status     TEXT NOT NULL,"                                         \
   275→    "   last_event_seq INTEGER NOT NULL"                                   \
   276→    ");"
   277→#endif /* EDU_SQL_SCHEMA */
   278→
   279→typedef struct {
   280→    ledger_projection_t base;
   281→    sqlite3*            db;
   282→} sqlite_proj_t;
   283→
   284→/* Error helper ----------------------------------------------------------- */
   285→static bool sqlite_check(int rc, sqlite3* db, char* err, size_t len)
   286→{
   287→    if (rc == SQLITE_OK || rc == SQLITE_DONE || rc == SQLITE_ROW) return true;
   288→    snprintf(err, len, "SQLite error %d: %s", rc, sqlite3_errmsg(db));
   289→    return false;
   290→}
   291→
   292→/* --- Interface implementations ----------------------------------------- */
   293→static ledger_projection_t* s_open(const char* dsn, char* err, size_t len)
   294→{
   295→    sqlite3* db = NULL;
   296→    int rc = sqlite3_open_v2(dsn ? dsn : ":memory:",
   297→                             &db,
   298→                             SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE | SQLITE_OPEN_FULLMUTEX,
   299→                             NULL);
   300→    if (!sqlite_check(rc, db, err, len)) return NULL;
   301→
   302→    rc = sqlite3_exec(db, EDU_SQL_SCHEMA, NULL, NULL, NULL);
   303→    if (!sqlite_check(rc, db, err, len)) { sqlite3_close(db); return NULL; }
   304→
   305→    sqlite_proj_t* p = calloc(1, sizeof *p);
   306→    if (!p) { strncpy(err, "OOM", len); sqlite3_close(db); return NULL; }
   307→    p->db = db;
   308→    return (ledger_projection_t*)p;
   309→}
   310→
   311→static void s_close(ledger_projection_t* obj)
   312→{
   313→    sqlite_proj_t* p = (sqlite_proj_t*)obj;
   314→    if (!p) return;
   315→    sqlite3_close(p->db);
   316→    free(p);
   317→}
   318→
   319→static uint64_t s_last(ledger_projection_t* obj)
   320→{
   321→    sqlite_proj_t* p = (sqlite_proj_t*)obj;
   322→    uint64_t seq = 0;
   323→    sqlite3_stmt* stmt = NULL;
   324→    const char* sql = "SELECT seq FROM projection_cursor WHERE id = 0;";
   325→    if (sqlite3_prepare_v2(p->db, sql, -1, &stmt, NULL) == SQLITE_OK &&
   326→        sqlite3_step(stmt) == SQLITE_ROW)
   327→    {
   328→        seq = (uint64_t)sqlite3_column_int64(stmt, 0);
   329→    }
   330→    sqlite3_finalize(stmt);
   331→    return seq;
   332→}
   333→
   334→static bool s_update_cursor(sqlite_proj_t* p, uint64_t seq, char* err, size_t len)
   335→{
   336→    sqlite3_stmt* stmt = NULL;
   337→    const char* sql = "UPDATE projection_cursor SET seq = ? WHERE id = 0;";
   338→    int rc = sqlite3_prepare_v2(p->db, sql, -1, &stmt, NULL);
   339→    if (!sqlite_check(rc, p->db, err, len)) return false;
   340→
   341→    sqlite3_bind_int64(stmt, 1, (sqlite3_int64)seq);
   342→    rc = sqlite3_step(stmt);
   343→    sqlite3_finalize(stmt);
   344→    return sqlite_check(rc, p->db, err, len);
   345→}
   346→
   347→static bool handle_payment_initiated(sqlite_proj_t* p,
   348→                                     const evt_payment_initiated_t* e,
   349→                                     char* err, size_t len)
   350→{
   351→    const char* sql =
   352→        "INSERT INTO vw_payments(payment_id, student_id, currency, amount_minor, status, last_event_seq) "
   353→        "VALUES(?, ?, ?, ?, 'INITIATED', ?)"
   354→        "ON CONFLICT(payment_id) DO UPDATE SET "
   355→        "  student_id=excluded.student_id,"
   356→        "  currency=excluded.currency,"
   357→        "  amount_minor=excluded.amount_minor,"
   358→        "  status='INITIATED',"
   359→        "  last_event_seq=excluded.last_event_seq "
   360→        "WHERE excluded.last_event_seq > vw_payments.last_event_seq;";
   361→
   362→    sqlite3_stmt* stmt = NULL;
   363→    int rc = sqlite3_prepare_v2(p->db, sql, -1, &stmt, NULL);
   364→    if (!sqlite_check(rc, p->db, err, len)) return false;
   365→
   366→    sqlite3_bind_text(stmt, 1, e->payment_id, -1, SQLITE_STATIC);
   367→    sqlite3_bind_text(stmt, 2, e->student_id, -1, SQLITE_STATIC);
   368→    sqlite3_bind_text(stmt, 3, e->currency, -1, SQLITE_STATIC);
   369→    sqlite3_bind_int64(stmt, 4, (sqlite3_int64)e->amount_minor);
   370→    sqlite3_bind_int64(stmt, 5, (sqlite3_int64)e->hdr.sequence);
   371→
   372→    rc = sqlite3_step(stmt);
   373→    sqlite3_finalize(stmt);
   374→    return sqlite_check(rc, p->db, err, len);
   375→}
   376→
   377→static bool handle_payment_settled(sqlite_proj_t* p,
   378→                                   const evt_payment_settled_t* e,
   379→                                   char* err, size_t len)
   380→{
   381→    const char* sql =
   382→        "UPDATE vw_payments SET status='SETTLED', last_event_seq=? "
   383→        "WHERE payment_id=? AND ? > last_event_seq;";
   384→
   385→    sqlite3_stmt* stmt = NULL;
   386→    int rc = sqlite3_prepare_v2(p->db, sql, -1, &stmt, NULL);
   387→    if (!sqlite_check(rc, p->db, err, len)) return false;
   388→
   389→    sqlite3_bind_int64(stmt, 1, (sqlite3_int64)e->hdr.sequence);
   390→    sqlite3_bind_text(stmt, 2, e->payment_id, -1, SQLITE_STATIC);
   391→    sqlite3_bind_int64(stmt, 3, (sqlite3_int64)e->hdr.sequence);
   392→
   393→    rc = sqlite3_step(stmt);
   394→    sqlite3_finalize(stmt);
   395→    return sqlite_check(rc, p->db, err, len);
   396→}
   397→
   398→static bool s_handle(ledger_projection_t* obj, const ledger_event_t* e, char* err, size_t len)
   399→{
   400→    sqlite_proj_t* p = (sqlite_proj_t*)obj;
   401→
   402→    /* idempotency short-circuit */
   403→    if (e->any.hdr.sequence <= s_last(obj)) return true;
   404→
   405→    int rc = sqlite3_exec(p->db, "BEGIN IMMEDIATE TRANSACTION;", NULL, NULL, NULL);
   406→    if (!sqlite_check(rc, p->db, err, len)) return false;
   407→
   408→    bool ok = true;
   409→    switch (e->any.hdr.type) {
   410→        case EVT_PAYMENT_INITIATED:
   411→            ok = handle_payment_initiated(p, &e->initiated, err, len);
   412→            break;
   413→        case EVT_PAYMENT_SETTLED:
   414→            ok = handle_payment_settled(p, &e->settled, err, len);
   415→            break;
   416→        default:
   417→            /* unsupported events are ignored for this projection */
   418→            break;
   419→    }
   420→
   421→    if (ok) ok = s_update_cursor(p, e->any.hdr.sequence, err, len);
   422→
   423→    rc = sqlite3_exec(p->db, ok ? "COMMIT;" : "ROLLBACK;", NULL, NULL, NULL);
   424→    if (!sqlite_check(rc, p->db, err, len)) ok = false;
   425→
   426→    return ok;
   427→}
   428→
   429→/* --- VTable registration ----------------------------------------------- */
   430→static const ledger_projection_vtable_t VTABLE = {
   431→    .open          = s_open,
   432→    .close         = s_close,
   433→    .handle_event  = s_handle,
   434→    .last_sequence = s_last,
   435→};
   436→
   437→__attribute__((constructor))
   438→static void register_sqlite_projection(void)
   439→{
   440→    register_ledger_projection(&VTABLE);
   441→}
   442→```
