   445→
   446→## 7  Projection Registry (Shared)
   447→
   448→All adapters share a **singleton registry** so the application can load whichever is linked first.
   449→
   450→```c
   451→/* =========================================================================
   452→ * File:    src/eduledger/projection_registry.c
   453→ * Purpose: Adapter registry – decouples caller from implementation
   454→ * ========================================================================= */
   455→#include <pthread.h>
   456→#include <string.h>
   457→#include "eduledger/projection.h"
   458→
   459→static pthread_mutex_t                lock = PTHREAD_MUTEX_INITIALIZER;
   460→static const ledger_projection_vtable_t* active = NULL;
   461→
   462→bool register_ledger_projection(const ledger_projection_vtable_t* vtable)
   463→{
   464→    pthread_mutex_lock(&lock);
   465→    if (!active) active = vtable; /* first wins */
   466→    pthread_mutex_unlock(&lock);
   467→    return true;
   468→}
   469→
   470→ledger_projection_t* projection_open(const char* dsn, char* err, size_t len)
   471→{
   472→    if (!active) { strncpy(err, "No projection adapter registered", len); return NULL; }
   473→    return active->open(dsn, err, len);
   474→}
   475→
   476→void projection_close(ledger_projection_t* p)
   477→{
   478→    if (p && active) active->close(p);
   479→}
   480→
   481→bool projection_handle_event(ledger_projection_t* p, const ledger_event_t* e, char* err, size_t len)
   482→{
   483→    return p && active && active->handle_event(p, e, err, len);
   484→}
   485→
   486→uint64_t projection_last_sequence(ledger_projection_t* p)
   487→{
   488→    return (p && active) ? active->last_sequence(p) : 0;
   489→}
   490→```
