   494→## 8  Driver Loop Example
   495→
   496→The event store will invoke `projection_handle_event()` for each new commit.  
   497→For local testing we bundle a minimal CLI.
   498→
   499→```c
   500→/* =========================================================================
   501→ * File:    apps/projection_cli.c
   502→ * Purpose: Stand-alone tool to hydrate a projection DB from an event log
   503→ * ========================================================================= */
   504→#define _POSIX_C_SOURCE 200809L
   505→#include <stdio.h>
   506→#include <stdlib.h>
   507→#include <string.h>
   508→#include "eduledger/projection.h"
   509→
   510→static void die(const char* msg)
   511→{
   512→    fprintf(stderr, "fatal: %s\n", msg);
   513→    exit(EXIT_FAILURE);
   514→}
   515→
   516→/* Simulate reading newline-delimited events from stdin */
   517→static ledger_event_t parse_event(const char* line)
   518→{
   519→    ledger_event_t e = {0};
   520→    /* CSV: seq,type,payment,student,amount */
   521→    sscanf(line, "%lu,%d,%31[^,],%31[^,],%lu",
   522→           &e.any.hdr.sequence,
   523→           (int*)&e.any.hdr.type,
   524→           e.initiated.payment_id,
   525→           e.initiated.student_id,
   526→           &e.initiated.amount_minor);
   527→    e.any.hdr.ts_utc = time(NULL);
   528→    strcpy(e.initiated.currency, "USD");
   529→    return e;
   530→}
   531→
   532→int main(int argc, char* argv[])
   533→{
   534→    char err[256] = {0};
   535→    const char* dsn = argc > 1 ? argv[1] : "file:projection.db?cache=shared";
   536→
   537→    ledger_projection_t* p = projection_open(dsn, err, sizeof err);
   538→    if (!p) die(err);
   539→
   540→    char*  line = NULL;
   541→    size_t n    = 0;
   542→    while (getline(&line, &n, stdin) != -1) {
   543→        ledger_event_t evt = parse_event(line);
   544→        if (!projection_handle_event(p, &evt, err, sizeof err))
   545→            die(err);
   546→    }
   547→    free(line);
   548→
   549→    printf("Projection at sequence %lu\n", projection_last_sequence(p));
   550→    projection_close(p);
   551→    return 0;
   552→}
   553→```
