   118→static void
   119→saga_log_audit(disburse_stipend_saga_t *saga,
   120→               audit_severity_e         severity,
   121→               const char              *fmt,
   122→               ...)
   123→{
   124→    if (!saga || !saga->audit) { return; }
   125→
   126→    va_list args;
   127→    va_start(args, fmt);
   128→    audit_logger_vlog(saga->audit, severity, SAGA_TAG, saga->saga_id, fmt, args);
   129→    va_end(args);
   130→}
   131→
   132→static void
   133→saga_publish_event(disburse_stipend_saga_t *saga,
   134→                   const stipend_event_t   *event)
   135→{
   136→    if (!saga || !saga->event_bus || !event) { return; }
   137→
   138→    event_bus_publish(saga->event_bus, (const event_base_t *)event);
   139→}
