   141→/* -------------------------------------------------------------------------- */
   142→/*  Forward Step Implementations                                              */
   143→/* -------------------------------------------------------------------------- */
   144→
   145→/* ---- Step 1: Compliance Check ------------------------------------------- */
   146→static bool
   147→step_compliance_check(disburse_stipend_saga_t *saga)
   148→{
   149→    stipend_event_t ev = {0};
   150→
   151→    saga_log_audit(saga, AUDIT_INFO, "Running compliance checks…");
   152→
   153→    compliance_result_t res = compliance_service_check(
   154→        saga->compliance,
   155→        &saga->request->student,
   156→        &saga->request->payout_details);
   157→
   158→    if (res.status != COMPLIANCE_STATUS_OK)
   159→    {
   160→        saga_log_audit(saga, AUDIT_WARN,
   161→                       "Compliance check failed — reason: %s",
   162→                       res.reason);
   163→
   164→        ev.type              = STIPEND_EVENT_COMPLIANCE_FAILED;
   165→        ev.stipend_request   = *saga->request;
   166→        strncpy(ev.reason, res.reason, sizeof(ev.reason) - 1);
   167→        saga_publish_event(saga, &ev);
   168→
   169→        errno = EACCES; /* Permission denied / non-compliant */
   170→        return false;
   171→    }
   172→
   173→    saga_log_audit(saga, AUDIT_INFO, "Compliance passed.");
   174→    ev.type            = STIPEND_EVENT_COMPLIANCE_PASSED;
   175→    ev.stipend_request = *saga->request;
   176→    saga_publish_event(saga, &ev);
   177→
   178→    saga->state = SAGA_STATE_COMPLIANCE_PASSED;
   179→    return true;
   180→}
   181→
   182→/* Compensation: no action needed for compliance                            */
   183→static bool
   184→compensate_compliance(__attribute__((unused)) disburse_stipend_saga_t *saga)
   185→{
   186→    return true; /* Idempotent – nothing to undo */
   187→}
   188→
   189→/* ---- Step 2: Reserve Funds ---------------------------------------------- */
   190→static bool
   191→step_reserve_funds(disburse_stipend_saga_t *saga)
   192→{
   193→    saga_log_audit(saga, AUDIT_INFO, "Reserving funds…");
   194→
   195→    payment_reservation_t reservation = {0};
   196→    int rc = payment_gateway_reserve(
   197→        saga->gateway,
   198→        &saga->request->payout_details,
   199→        &reservation);
   200→
   201→    if (rc != 0)
   202→    {
   203→        saga_log_audit(saga, AUDIT_ERROR,
   204→                       "Fund reservation failed (err=%d)", rc);
   205→        errno = rc;
   206→        return false;
   207→    }
   208→
   209→    /* Persist reservation token on stipend aggregate for later capture */
   210→    stipend_repository_attach_reservation(
   211→        saga->stipend_repo,
   212→        saga->request->stipend_id,
   213→        &reservation);
   214→
   215→    saga->state = SAGA_STATE_FUNDS_RESERVED;
   216→    return true;
   217→}
   218→
   219→static bool
   220→compensate_reserve_funds(disburse_stipend_saga_t *saga)
   221→{
   222→    /* Release reservation only if it exists */
   223→    saga_log_audit(saga, AUDIT_INFO, "Releasing reserved funds (rollback)…");
   224→
   225→    /* Retrieve token back from stipend aggregate */
   226→    payment_reservation_t token = {0};
   227→    int rc = stipend_repository_get_reservation(
   228→        saga->stipend_repo,
   229→        saga->request->stipend_id,
   230→        &token);
   231→
   232→    if (rc != 0)
   233→    {
   234→        saga_log_audit(saga, AUDIT_ERROR,
   235→                       "Failed to fetch reservation token (err=%d)", rc);
   236→        return false;
   237→    }
   238→
   239→    rc = payment_gateway_release(saga->gateway, &token);
   240→    if (rc != 0)
   241→    {
   242→        saga_log_audit(saga, AUDIT_ERROR,
   243→                       "Fund release failed (err=%d)", rc);
   244→        return false;
   245→    }
   246→    return true;
   247→}
   248→
   249→/* ---- Step 3: Ledger Posting --------------------------------------------- */
   250→static bool
   251→step_ledger_post(disburse_stipend_saga_t *saga)
   252→{
   253→    saga_log_audit(saga, AUDIT_INFO, "Posting ledger entry…");
   254→
   255→    ledger_entry_t entry = {
   256→        .entry_id       = "",
   257→        .timestamp      = timestamp_now(),
   258→        .type           = LEDGER_ENTRY_STIPEND_DISBURSEMENT,
   259→        .amount         = saga->request->payout_details.amount,
   260→        .currency       = saga->request->payout_details.currency,
   261→        .student_id     = saga->request->student.student_id,
   262→        .correlation_id = saga->saga_id
   263→    };
   264→
   265→    uuid_generate(entry.entry_id, sizeof(entry.entry_id));
   266→
   267→    int rc = ledger_repository_append(saga->ledger_repo, &entry);
   268→    if (rc != 0)
   269→    {
   270→        saga_log_audit(saga, AUDIT_ERROR,
   271→                       "Ledger append failed (err=%d)", rc);
   272→        errno = rc;
   273→        return false;
   274→    }
   275→
   276→    saga->state = SAGA_STATE_LEDGER_POSTED;
   277→    return true;
   278→}
   279→
   280→static bool
   281→compensate_ledger_post(disburse_stipend_saga_t *saga)
   282→{
   283→    saga_log_audit(saga, AUDIT_INFO, "Reversing ledger entry (rollback)…");
   284→
   285→    int rc = ledger_repository_reversal(
   286→        saga->ledger_repo,
   287→        saga->request->student.student_id,
   288→        saga->saga_id); /* correlation_id */
   289→
   290→    if (rc != 0)
   291→    {
   292→        saga_log_audit(saga, AUDIT_ERROR,
   293→                       "Ledger reversal failed (err=%d)", rc);
   294→        return false;
   295→    }
   296→    return true;
   297→}
   298→
   299→/* ---- Step 4: Capture / Disburse Funds ------------------------------------ */
   300→static bool
   301→step_capture_funds(disburse_stipend_saga_t *saga)
   302→{
   303→    saga_log_audit(saga, AUDIT_INFO,
   304→                   "Capturing reserved funds to student account…");
   305→
   306→    payment_reservation_t token = {0};
   307→    int rc = stipend_repository_get_reservation(
   308→        saga->stipend_repo,
   309→        saga->request->stipend_id,
   310→        &token);
   311→
   312→    if (rc != 0)
   313→    {
   314→        saga_log_audit(saga, AUDIT_ERROR,
   315→                       "Reservation token missing (err=%d)", rc);
   316→        errno = rc;
   317→        return false;
   318→    }
   319→
   320→    rc = payment_gateway_capture(saga->gateway, &token);
   321→    if (rc != 0)
   322→    {
   323→        saga_log_audit(saga, AUDIT_ERROR,
   324→                       "Fund capture failed (err=%d)", rc);
   325→        errno = rc;
   326→        return false;
   327→    }
   328→
   329→    saga->state = SAGA_STATE_DISBURSED;
   330→    return true;
   331→}
   332→
   333→static bool
   334→compensate_capture_funds(disburse_stipend_saga_t *saga)
   335→{
   336→    /* Attempt refund only if capture was successful */
   337→    saga_log_audit(saga, AUDIT_INFO,
   338→                   "Refunding captured funds (rollback)…");
   339→
   340→    payment_reservation_t token = {0};
   341→    int rc = stipend_repository_get_reservation(
   342→        saga->stipend_repo,
   343→        saga->request->stipend_id,
   344→        &token);
   345→
   346→    if (rc != 0)
   347→    {
   348→        saga_log_audit(saga, AUDIT_ERROR,
   349→                       "Reservation token missing for refund (err=%d)", rc);
   350→        return false;
   351→    }
   352→
   353→    rc = payment_gateway_refund(saga->gateway, &token);
   354→    if (rc != 0)
   355→    {
   356→        saga_log_audit(saga, AUDIT_ERROR,
   357→                       "Refund failed (err=%d)", rc);
   358→        return false;
   359→    }
   360→    return true;
   361→}
   362→
   363→/* -------------------------------------------------------------------------- */
   364→/*  Saga Steps Array                                                          */
   365→/* -------------------------------------------------------------------------- */
   366→
   367→static saga_step_t g_saga_steps[] = {
   368→    { "COMPLIANCE_CHECK",      step_compliance_check,  compensate_compliance   },
   369→    { "RESERVE_FUNDS",         step_reserve_funds,     compensate_reserve_funds},
   370→    { "LEDGER_POST",           step_ledger_post,       compensate_ledger_post },
   371→    { "CAPTURE_FUNDS",         step_capture_funds,     compensate_capture_funds}
   372→};
   373→
   374→#define SAGA_TOTAL_STEPS (sizeof(g_saga_steps) / sizeof(g_saga_steps[0]))
   375→
   376→/* -------------------------------------------------------------------------- */
   377→/*  Public API                                                                */
   378→/* -------------------------------------------------------------------------- */
   379→
   380→/**
   381→ * disburse_stipend_run
   382→ *
   383→ * Execute the Disburse Stipend Saga for a given stipend request.
   384→ *
   385→ * return: 0 on success, or a negative errno code on failure.
   386→ */
   387→int
   388→disburse_stipend_run(
   389→    const stipend_request_t  *request,
   390→    compliance_service_t     *compliance,
   391→    payment_gateway_t        *gateway,
   392→    ledger_repository_t      *ledger_repo,
   393→    stipend_repository_t     *stipend_repo,
   394→    event_bus_t              *event_bus,
   395→    audit_logger_t           *audit,
   396→    retry_policy_t            retry_policy)
   397→{
   398→    if (!request || !compliance || !gateway || !ledger_repo ||
   399→        !stipend_repo || !event_bus || !audit)
   400→    {
   401→        return EINVAL;
   402→    }
   403→
   404→    /* ------------------------------------------------------------------ */
   405→    /*  Instantiate saga context                                           */
   406→    /* ------------------------------------------------------------------ */
   407→    disburse_stipend_saga_t saga = {
   408→        .compliance   = compliance,
   409→        .gateway      = gateway,
   410→        .ledger_repo  = ledger_repo,
   411→        .stipend_repo = stipend_repo,
   412→        .event_bus    = event_bus,
   413→        .audit        = audit,
   414→        .state        = SAGA_STATE_NOT_STARTED,
   415→        .retry_policy = retry_policy,
   416→        .request      = request,
   417→        .steps        = g_saga_steps,
   418→        .step_count   = SAGA_TOTAL_STEPS,
   419→        .started_at   = timestamp_now()
   420→    };
   421→    uuid_generate(saga.saga_id, sizeof(saga.saga_id));
   422→
   423→    saga_log_audit(&saga, AUDIT_INFO,
   424→                   "Saga %s (%s) started for Stipend #%s.",
   425→                   saga.saga_id, SAGA_VERSION, request->stipend_id);
   426→
   427→    /* ------------------------------------------------------------------ */
   428→    /*  Forward execution                                                 */
   429→    /* ------------------------------------------------------------------ */
   430→    ssize_t current_step = 0;
   431→    for (; current_step < (ssize_t)saga.step_count; ++current_step)
   432→    {
   433→        const saga_step_t *step = &saga.steps[current_step];
   434→        size_t attempt = 0;
   435→
   436→        saga_log_audit(&saga, AUDIT_DEBUG, "→ Executing step: %s", step->name);
   437→
   438→        while (attempt <= saga.retry_policy.max_retries)
   439→        {
   440→            if (step->forward(&saga))
   441→            {
   442→                /* Success */
   443→                break;
   444→            }
   445→
   446→            attempt++;
   447→            if (attempt > saga.retry_policy.max_retries)
   448→            {
   449→                /* Abort forward flow */
   450→                saga_log_audit(&saga, AUDIT_WARN,
   451→                               "Step %s exhausted retry budget.", step->name);
   452→                goto rollback; /* Begin compensation */
   453→            }
   454→
   455→            /* Wait before retry */
   456→            uint32_t backoff_ms = retry_policy_backoff(&saga.retry_policy, attempt);
   457→            saga_log_audit(&saga, AUDIT_INFO,
   458→                           "Retrying step %s in %ums (attempt %zu)…",
   459→                           step->name, backoff_ms, attempt);
   460→
   461→            retry_policy_sleep(backoff_ms);
   462→        }
   463→    }
   464→
   465→    /* ------------------------------------------------------------------ */
   466→    /*  Completed successfully                                            */
   467→    /* ------------------------------------------------------------------ */
   468→    saga.state = SAGA_STATE_COMPLETED;
   469→    saga_log_audit(&saga, AUDIT_INFO,
   470→                   "Saga %s completed successfully.", saga.saga_id);
   471→
   472→    stipend_event_t ev = {
   473→        .type            = STIPEND_EVENT_DISBURSED,
   474→        .stipend_request = *request
   475→    };
   476→    saga_publish_event(&saga, &ev);
   477→    return 0;
   478→
   479→/* -------------------------------------------------------------------------- */
   480→/*  Compensation / Rollback Flow                                              */
   481→/* -------------------------------------------------------------------------- */
   482→rollback:
   483→    saga.state = SAGA_STATE_ROLLING_BACK;
   484→    saga_log_audit(&saga, AUDIT_WARN,
   485→                   "Initiating rollback of Saga %s…", saga.saga_id);
   486→
   487→    for (ssize_t i = current_step; i >= 0; --i)
   488→    {
   489→        const saga_step_t *step = &saga.steps[i];
   490→        saga_log_audit(&saga, AUDIT_DEBUG,
   491→                       "↩ Compensating step: %s", step->name);
   492→
   493→        if (!step->compensate(&saga))
   494→        {
   495→            saga_log_audit(&saga, AUDIT_ERROR,
   496→                           "Compensation for step %s failed.", step->name);
   497→            /* Compensation failures are logged, but saga continues */
   498→        }
   499→    }
   500→
   501→    saga.state = SAGA_STATE_FAILED;
   502→
   503→    stipend_event_t failed_ev = {
   504→        .type            = STIPEND_EVENT_DISBURSEMENT_FAILED,
   505→        .stipend_request = *request
   506→    };
   507→    strncpy(failed_ev.reason, "Saga rollback completed", sizeof(failed_ev.reason) - 1);
   508→    saga_publish_event(&saga, &failed_ev);
   509→
   510→    saga_log_audit(&saga, AUDIT_WARN,
   511→                   "Saga %s rolled back. Stipend disbursement aborted.",
   512→                   saga.saga_id);
   513→
   514→    /* Preserve original errno set by failing step */
   515→    return errno ? errno : ECANCELED;
   516→}
   517→
   518→/* -------------------------------------------------------------------------- */
   519→/*  End of file                                                               */
   520→/* -------------------------------------------------------------------------- */
