    99→/* -------------------------------------------------------------------------- */
   100→/*  Saga Orchestration – Callback VTable                                      */
   101→/* -------------------------------------------------------------------------- */
   102→/*
   103→ *  The saga never performs I/O directly.  All side-effects are routed through
   104→ *  a set of callbacks supplied by the calling application/service.  Each
   105→ *  callback must be idempotent because the saga might retry crashed steps.
   106→ *
   107→ *  Every callback returns `true` on success.  On failure it returns `false`
   108→ *  and must populate `err_out`.
   109→ */
   110→
   111→typedef bool (*validate_eligibility_fn)(
   112→        const stipend_disbursement_request_t *req,
   113→        saga_error_t                         *err_out);
   114→
   115→typedef bool (*reserve_budget_fn)(
   116→        const stipend_disbursement_request_t *req,
   117→        uint64_t                             *reservation_id_out,
   118→        saga_error_t                         *err_out);
   119→
   120→typedef bool (*release_budget_fn)(
   121→        uint64_t       reservation_id,
   122→        saga_error_t  *err_out);
   123→
   124→typedef bool (*initiate_transfer_fn)(
   125→        const stipend_disbursement_request_t *req,
   126→        uint64_t                             *network_tx_id_out,
   127→        saga_error_t                         *err_out);
   128→
   129→typedef bool (*reverse_transfer_fn)(
   130→        uint64_t       network_tx_id,
   131→        saga_error_t  *err_out);
   132→
   133→typedef bool (*record_ledger_entry_fn)(
   134→        const stipend_disbursement_request_t *req,
   135→        const char                           *entry_type,
   136→        uint64_t                              related_id, /* reservation or tx id */
   137→        saga_error_t                         *err_out);
   138→
   139→typedef bool (*publish_domain_event_fn)(
   140→        const stipend_disbursement_request_t *req,
   141→        const char                           *event_name,
   142→        saga_error_t                         *err_out);
   143→
   144→/* -------------------------------------------------------------------------- */
   145→/*  VTable Container                                                          */
   146→/* -------------------------------------------------------------------------- */
   147→typedef struct {
   148→    validate_eligibility_fn   validate_eligibility;
   149→    reserve_budget_fn         reserve_budget;
   150→    release_budget_fn         release_budget;
   151→    initiate_transfer_fn      initiate_transfer;
   152→    reverse_transfer_fn       reverse_transfer;
   153→    record_ledger_entry_fn    record_ledger_entry;
   154→    publish_domain_event_fn   publish_domain_event;
   155→} stipend_disbursement_callbacks_t;
   156→
   157→/* Utility macro to check if a pointer in the vtable is missing at runtime. */
   158→#define _CHECK_CB(cb) do {                                                  \
   159→    if ((cb) == NULL) {                                                     \
   160→        if (err_out) {                                                      \
   161→            err_out->code = SAGA_ERR_INTERNAL;                              \
   162→            snprintf(err_out->message, sizeof(err_out->message),            \
   163→                     "Callback missing: %s", #cb);                          \
   164→        }                                                                   \
   165→        return false;                                                       \
   166→    } } while (0)
   167→
   168→/* -------------------------------------------------------------------------- */
   169→/*  Saga Public API                                                           */
   170→/* -------------------------------------------------------------------------- */
   171→static inline
   172→bool disburse_stipend_run(
   173→        const stipend_disbursement_request_t   *req,
   174→        const stipend_disbursement_callbacks_t *cb,
   175→        saga_error_t                           *err_out);
   176→
   177→/* -------------------------------------------------------------------------- */
   178→/*  Implementation                                                            */
   179→/* -------------------------------------------------------------------------- */
   180→static inline
   181→bool disburse_stipend_run(
   182→        const stipend_disbursement_request_t   *req,
   183→        const stipend_disbursement_callbacks_t *cb,
   184→        saga_error_t                           *err_out)
   185→{
   186→    /* Defensive programming: never trust caller. */
   187→    if (!req || !cb) {
   188→        if (err_out) {
   189→            err_out->code = SAGA_ERR_INTERNAL;
   190→            snprintf(err_out->message, sizeof(err_out->message),
   191→                     "NULL argument(s) received");
   192→        }
   193→        return false;
   194→    }
   195→
   196→    uint64_t reservation_id = 0;
   197→    uint64_t network_tx_id  = 0;
   198→
   199→    /* ------------------------------------------------------------------ */
   200→    /* 1. Validate eligibility                                            */
   201→    /* ------------------------------------------------------------------ */
   202→    _CHECK_CB(cb->validate_eligibility);
   203→    if (!cb->validate_eligibility(req, err_out)) {
   204→        return false; /* validation errors are final, no compensation needed */
   205→    }
   206→
   207→    /* ------------------------------------------------------------------ */
   208→    /* 2. Reserve budget (Financial-Aid allocation ledger)                */
   209→    /* ------------------------------------------------------------------ */
   210→    _CHECK_CB(cb->reserve_budget);
   211→    if (!cb->reserve_budget(req, &reservation_id, err_out)) {
   212→        return false;
   213→    }
   214→
   215→    /* ------------------------------------------------------------------ */
   216→    /* 3. Initiate transfer via payment network                           */
   217→    /* ------------------------------------------------------------------ */
   218→    _CHECK_CB(cb->initiate_transfer);
   219→    if (!cb->initiate_transfer(req, &network_tx_id, err_out)) {
   220→
   221→        /* ------------------------------------------------------------------
   222→         * Compensation Path #1: release the budget reservation
   223→         * ------------------------------------------------------------------ */
   224→        _CHECK_CB(cb->release_budget);
   225→        saga_error_t cmp_err = SAGA_ERROR_INIT();
   226→        if (!cb->release_budget(reservation_id, &cmp_err)) {
   227→            /* Fatal: both forward step + compensation failed */
   228→            if (err_out && err_out->code == SAGA_OK) {
   229→                *err_out = cmp_err;
   230→            }
   231→            return false;
   232→        }
   233→
   234→        return false; /* original error already populated by initiate_transfer */
   235→    }
   236→
   237→    /* ------------------------------------------------------------------ */
   238→    /* 4. Record ledger entry (financial book-keeping)                    */
   239→    /* ------------------------------------------------------------------ */
   240→    _CHECK_CB(cb->record_ledger_entry);
   241→    if (!cb->record_ledger_entry(req, "STIPEND_DISBURSEMENT", network_tx_id, err_out)) {
   242→
   243→        /* Compensation Path #2: reverse transfer + release budget */
   244→        _CHECK_CB(cb->reverse_transfer);
   245→        _CHECK_CB(cb->release_budget);
   246→
   247→        saga_error_t cmp_err1 = SAGA_ERROR_INIT();
   248→        if (!cb->reverse_transfer(network_tx_id, &cmp_err1)) {
   249→            if (err_out && err_out->code == SAGA_OK) *err_out = cmp_err1;
   250→            /* Deliberately fall through to attempt second compensation */
   251→        }
   252→
   253→        saga_error_t cmp_err2 = SAGA_ERROR_INIT();
   254→        if (!cb->release_budget(reservation_id, &cmp_err2)) {
   255→            if (err_out && err_out->code == SAGA_OK) *err_out = cmp_err2;
   256→        }
   257→
   258→        return false;
   259→    }
   260→
   261→    /* ------------------------------------------------------------------ */
