   274→        cb->reverse_transfer(network_tx_id, &cmp_err);
   275→        cb->release_budget(reservation_id, &cmp_err);
   276→
   277→        return false;
   278→    }
   279→
   280→    /* ------------------------------------------------------------------ */
   281→    /* 6. Success!                                                        */
   282→    /* ------------------------------------------------------------------ */
   283→    if (err_out) {
   284→        *err_out = SAGA_ERROR_INIT(); /* reset to success */
   285→    }
   286→    return true;
   287→}
