   206→/* ────────────────────────────────────────────────────────────────────────── */
   207→/*                           Projector Context                                */
   208→/* ────────────────────────────────────────────────────────────────────────── */
   209→
   210→typedef struct {
   211→    dashboard_snapshot_t state;
   212→    projection_store_t  *store;
   213→    pthread_mutex_t      mtx;
   214→} dashboard_projector_t;
   215→
   216→/* ────────────────────────────────────────────────────────────────────────── */
   217→/*                           Public Functions                                 */
   218→/* ────────────────────────────────────────────────────────────────────────── */
   219→
   220→/*
   221→ * projector_create
   222→ *   Allocates a new projector and hydrates its state from the store.
   223→ *
   224→ *   Returns NULL on allocation or persistence failure.
   225→ */
   226→dashboard_projector_t *
   227→dashboard_projector_create(projection_store_t *store) {
   228→    if (!store) {
   229→        store = file_store_create(NULL);
   230→        if (!store) {
   231→            return NULL;
   232→        }
   233→    }
   234→
   235→    dashboard_projector_t *proj = calloc(1, sizeof(*proj));
   236→    if (!proj) {
   237→        store->destroy(store);
   238→        return NULL;
   239→    }
   240→
   241→    proj->store = store;
   242→    pthread_mutex_init(&proj->mtx, NULL);
   243→
   244→    /* Load existing snapshot, if any */
   245→    if (store->load(store, &proj->state) != 0) {
   246→        DASHBOARD_PROJECTOR_LOG("Failed to load snapshot – aborting");
   247→        pthread_mutex_destroy(&proj->mtx);
   248→        store->destroy(store);
   249→        free(proj);
   250→        return NULL;
   251→    }
   252→
   253→    return proj;
   254→}
   255→
   256→/*
   257→ * projector_destroy
   258→ *   Persists the final state and frees resources.
   259→ */
   260→void dashboard_projector_destroy(dashboard_projector_t *proj) {
   261→    if (!proj) {
   262→        return;
   263→    }
   264→
   265→    pthread_mutex_lock(&proj->mtx);
   266→    proj->store->save(proj->store, &proj->state);
   267→    pthread_mutex_unlock(&proj->mtx);
