   270→    pthread_mutex_destroy(&proj->mtx);
   271→    free(proj);
   272→}
   273→
   274→/*
   275→ * dashboard_projector_snapshot
   276→ *   Returns a copy of the current read-model for external queries.
   277→ *   Caller owns the return value.
   278→ */
   279→dashboard_snapshot_t
