   286→}
   287→
   288→/*
   289→ * dashboard_projector_handle
   290→ *   Consumes a domain event and mutates the projection atomically.
   291→ */
   292→int dashboard_projector_handle(dashboard_projector_t *proj,
   293→                               const domain_event_t *event) {
   294→    if (!proj || !event) {
   295→        return -1;
   296→    }
   297→
   298→    pthread_mutex_lock(&proj->mtx);
   299→
   300→    /* Ensure idempotency */
   301→    if (event->sequence_number <= proj->state.last_sequence_number) {
   302→        pthread_mutex_unlock(&proj->mtx);
   303→        return 0;
   304→    }
   305→
   306→    switch (event->type) {
   307→    case EVENT_PAYMENT_INITIATED:
   308→        proj->state.total_payments++;
   309→        proj->state.pending_payments++;
   310→        break;
