   312→    case EVENT_PAYMENT_SETTLED:
   313→        if (proj->state.pending_payments > 0) {
   314→            proj->state.pending_payments--;
   315→        }
   316→        if (event->data.payment_settled.success) {
   317→            proj->state.total_tuition +=
   318→                event->data.payment_settled.amount;
   319→        }
   320→        break;
   321→
   322→    case EVENT_FRAUD_ALERT:
   323→        proj->state.fraud_alerts++;
   324→        break;
   325→
   326→    default:
   327→        DASHBOARD_PROJECTOR_LOG("Unknown event type: %d", event->type);
   328→        break;
   329→    }
   330→
   331→    proj->state.last_sequence_number = event->sequence_number;
   332→
   333→    /* Best-effort persistence; if it fails we keep working but log an error */
