    49→    PPC_MAX_TRACE_ID_LEN    = 64,   /* Trace / Span IDs for distributed tracing      */
    50→    PPC_MAX_CCY_LEN         = 4,    /* ISO-4217 (3 letters + NULL)                  */
    51→    PPC_MAX_ERRBUF          = 128   /* Generic error buffer size                    */
    52→};
    53→
    54→/* ────────────────────────────────────────────────────────────────────────── */
    55→/* Error Codes specific to ProcessPaymentCommand                             */
    56→typedef enum ppc_error_e
    57→{
    58→    PPC_OK = 0,
    59→    PPC_EINVAL,           /* Generic invalid argument                         */
    60→    PPC_EOVERFLOW,        /* Value out of range                               */
    61→    PPC_EUNSUPPORTED,     /* Unsupported currency / payment type              */
    62→    PPC_EAMOUNT_NEGATIVE  /* Negative amount not allowed                      */
    63→} ppc_error_t;
    64→
    65→/* ────────────────────────────────────────────────────────────────────────── */
    66→/* Monetary value object (value-semantics, immutable after init)             */
    67→typedef struct ppc_money_s
    68→{
    69→    int64_t     minor_units;                /* For USD cents, EUR cents, etc.        */
    70→    char        currency[PPC_MAX_CCY_LEN];  /* 3-char ISO code, NULL-terminated      */
    71→} ppc_money_t;
    72→
    73→static inline ppc_money_t
    74→ppc_money_make(int64_t minor_units, const char *iso_currency)
    75→{
    76→    ppc_money_t m = { .minor_units = minor_units };
    77→    if (iso_currency != NULL)
    78→    {
    79→        strncpy(m.currency, iso_currency, PPC_MAX_CCY_LEN - 1);
    80→        m.currency[PPC_MAX_CCY_LEN - 1] = '\0';
    81→    }
    82→    else
    83→    {
    84→        m.currency[0] = '\0';
    85→    }
    86→    return m;
    87→}
    88→
    89→/* ────────────────────────────────────────────────────────────────────────── */
    90→/* Flags for optional payment behaviors                                      */
    91→typedef enum ppc_flags_e
    92→{
    93→    PPC_FLAG_NONE              = 0x00000000u,
    94→    PPC_FLAG_MFA_REQUIRED      = 0x00000001u,   /* Multi-Factor Auth required        */
    95→    PPC_FLAG_FORCE_SETTLEMENT  = 0x00000002u,   /* Bypass risk checks (admin only!)  */
    96→    PPC_FLAG_SAGA_STEP         = 0x00000004u    /* Part of ongoing Saga transaction  */
    97→} ppc_flags_t;
    98→
    99→/* ────────────────────────────────────────────────────────────────────────── */
   100→/* ProcessPaymentCommand DTO                                                 */
   101→typedef struct process_payment_command_s
   102→{
   103→    char            student_id[PPC_MAX_ID_LEN];
   104→    char            account_id[PPC_MAX_ID_LEN];
   105→    char            correlation_id[PPC_MAX_ID_LEN];
   106→    char            trace_id[PPC_MAX_TRACE_ID_LEN];  /* OpenTelemetry trace linkage */
   107→
   108→    ppc_money_t     amount;             /* Immutable monetary value                 */
   109→    time_t          request_ts;         /* Request creation time                    */
   110→    time_t          due_date;           /* Optional future execution (0 = immediate)*/
   111→
   112→    uint32_t        flags;              /* See ppc_flags_t                          */
   113→    /* Extensible metadata map could be added here with a pointer ‑ excluded
   114→       to keep the struct POD-like and easy to serialize inside the course.    */
   115→} process_payment_command_t;
   116→
   117→/* Validate field size assumptions at compile-time                            */
   118→PPC_STATIC_ASSERT(sizeof(process_payment_command_t) <
   119→                  512, process_payment_command_must_remain_small);
   120→
   121→/* ────────────────────────────────────────────────────────────────────────── */
   122→/* Helper Functions (inline for header-only distribution)                    */
   123→
   124→/*
   125→ *  ppc_validate_iso_currency():
   126→ *      Minimal ISO-4217 upper-case alpha-3 validation.  This intentionally
   127→ *      does NOT check against a whitelist to avoid hardcoding currencies in
   128→ *      the application layer.  Domain layer will perform full validation.
   129→ */
   130→static inline bool
   131→ppc_validate_iso_currency(const char *ccy)
   132→{
   133→    if (!ccy || strlen(ccy) != 3)
   134→        return false;
   135→
   136→    for (size_t i = 0; i < 3; ++i)
   137→    {
   138→        if (ccy[i] < 'A' || ccy[i] > 'Z')
   139→            return false;
   140→    }
   141→    return true;
   142→}
   143→
   144→/*
   145→ *  process_payment_command_init():
   146→ *      Populate a command instance and perform light validation so that
   147→ *      callers do not accidentally create malformed objects.
   148→ *
   149→ *      Parameters:
   150→ *          cmd         (out)   Pre-allocated struct to populate
   151→ *          student_id  (in)    Student identifier (NULL-terminated)
   152→ *          account_id  (in)    Ledger / wallet identifier
   153→ *          amount      (in)    Monetary value object
   154→ *          correlation (in)    Correlation ID for idempotency ‑ optional
   155→ *          trace_id    (in)    Distributed tracing ID               ‑ optional
   156→ *          due_date    (in)    Epoch seconds at which payment executes
   157→ *          flags       (in)    Command flags
   158→ *          errbuf      (out)   Optional buffer for human-readable error
   159→ *          errlen      (in)    Size of errbuf
   160→ *
   161→ *      Returns:
   162→ *          PPC_OK on success, otherwise error-code.
   163→ */
   164→static inline ppc_error_t
   165→process_payment_command_init(process_payment_command_t *cmd,
   166→                             const char *student_id,
   167→                             const char *account_id,
   168→                             ppc_money_t amount,
   169→                             const char *correlation,
   170→                             const char *trace_id,
   171→                             time_t due_date,
   172→                             uint32_t flags,
   173→                             char *errbuf,
   174→                             size_t errlen)
   175→{
   176→    if (cmd == NULL || student_id == NULL || account_id == NULL)
   177→        return PPC_EINVAL;
   178→
   179→    if (snprintf(cmd->student_id, sizeof(cmd->student_id), "%s", student_id) >=
   180→        (int)sizeof(cmd->student_id))
   181→    {
   182→        if (errbuf && errlen)
   183→            strncpy(errbuf, "student_id too long", errlen - 1);
   184→        return PPC_EOVERFLOW;
   185→    }
   186→
   187→    if (snprintf(cmd->account_id, sizeof(cmd->account_id), "%s", account_id) >=
   188→        (int)sizeof(cmd->account_id))
   189→    {
   190→        if (errbuf && errlen)
   191→            strncpy(errbuf, "account_id too long", errlen - 1);
   192→        return PPC_EOVERFLOW;
   193→    }
   194→
   195→    if (correlation && *correlation)
   196→    {
   197→        if (snprintf(cmd->correlation_id, sizeof(cmd->correlation_id), "%s",
   198→                     correlation) >= (int)sizeof(cmd->correlation_id))
   199→        {
   200→            if (errbuf && errlen)
   201→                strncpy(errbuf, "correlation_id too long", errlen - 1);
   202→            return PPC_EOVERFLOW;
   203→        }
   204→    }
   205→    else
   206→    {
   207→        cmd->correlation_id[0] = '\0';
   208→    }
   209→
   210→    if (trace_id && *trace_id)
   211→    {
   212→        if (snprintf(cmd->trace_id, sizeof(cmd->trace_id), "%s",
   213→                     trace_id) >= (int)sizeof(cmd->trace_id))
   214→        {
   215→            if (errbuf && errlen)
   216→                strncpy(errbuf, "trace_id too long", errlen - 1);
   217→            return PPC_EOVERFLOW;
   218→        }
   219→    }
   220→    else
   221→    {
   222→        cmd->trace_id[0] = '\0';
   223→    }
   224→
   225→    /* Monetary sanity checks */
   226→    if (amount.minor_units <= 0)
   227→    {
   228→        if (errbuf && errlen)
   229→            strncpy(errbuf, "amount must be positive", errlen - 1);
   230→        return PPC_EAMOUNT_NEGATIVE;
   231→    }
   232→
   233→    if (!ppc_validate_iso_currency(amount.currency))
   234→    {
   235→        if (errbuf && errlen)
   236→            strncpy(errbuf, "invalid ISO-4217 currency", errlen - 1);
   237→        return PPC_EUNSUPPORTED;
   238→    }
   239→    cmd->amount = amount;
   240→    cmd->flags  = flags;
   241→    cmd->due_date = due_date;
   242→    cmd->request_ts = time(NULL);
   243→
   244→    return PPC_OK;
   245→}
   246→
   247→/*
   248→ *  process_payment_command_is_valid():
   249→ *      Perform additional validation that may be required just before the
   250→ *      command is executed.  This is separated from _init() so that tests
   251→ *      can mutate the command struct (e.g. tamper scenarios) and re-validate
   252→ *      without constructing a new object.
   253→ *
   254→ *      Returns:
   255→ *          true  -> looks sane
   256→ *          false -> invalid; details in errbuf if provided
   257→ */
   258→static inline bool
   259→process_payment_command_is_valid(const process_payment_command_t *cmd,
   260→                                 char *errbuf,
   261→                                 size_t errlen)
   262→{
   263→    if (!cmd)
   264→        return false;
   265→
   266→    if (cmd->student_id[0] == '\0')
   267→    {
   268→        if (errbuf && errlen)
   269→            strncpy(errbuf, "missing student_id", errlen - 1);
   270→        return false;
   271→    }
   272→
   273→    if (cmd->account_id[0] == '\0')
   274→    {
   275→        if (errbuf && errlen)
   276→            strncpy(errbuf, "missing account_id", errlen - 1);
   277→        return false;
   278→    }
   279→
   280→    if (cmd->amount.minor_units <= 0)
   281→    {
   282→        if (errbuf && errlen)
   283→            strncpy(errbuf, "amount must be positive", errlen - 1);
   284→        return false;
   285→    }
   286→
   287→    if (!ppc_validate_iso_currency(cmd->amount.currency))
   288→    {
   289→        if (errbuf && errlen)
   290→            strncpy(errbuf, "invalid currency code", errlen - 1);
   291→        return false;
   292→    }
   293→
   294→    /* Example business rule:  cannot force settlement AND require MFA */
   295→    if ((cmd->flags & PPC_FLAG_FORCE_SETTLEMENT) &&
   296→        (cmd->flags & PPC_FLAG_MFA_REQUIRED))
   297→    {
   298→        if (errbuf && errlen)
   299→            strncpy(errbuf, "mutually exclusive flags set", errlen - 1);
   300→        return false;
   301→    }
   302→
   303→    return true;
   304→}
   305→
   306→/*
   307→ *  process_payment_command_clear():
   308→ *      Zero-out all fields to protect sensitive data before freeing or
   309→ *      re-using the struct.  Although most fields are not secret, we teach
   310→ *      students to wipe memory that might contain personally identifiable
   311→ *      information (PII) or payment data.
   312→ */
   313→static inline void
   314→process_payment_command_clear(process_payment_command_t *cmd)
   315→{
   316→    if (cmd)
   317→        memset(cmd, 0, sizeof(*cmd));
   318→}
   319→
   320→#endif /* EDUPAY_BURSAR_APP_COMMANDS_PROCESS_PAYMENT_COMMAND_H */
   321→

