audit_logger_log(audit, AUDIT_INFO, "AUTO_PAYMENT",
    "amount_calculated", student_id, saga_id,
    "Auto-payment amount: %ld cents (stipend: %ld, balance: %ld).",
    amount_to_apply, stipend_amount, outstanding_balance);

audit_logger_log(audit, AUDIT_INFO, "AUTO_PAYMENT",
    "applied_to_tuition", student_id, saga_id,
    "Stipend %s applied to tuition account %s.",
    stipend_id, tuition_account_id);
```

